def _open_optional_log_handle(_filepath):
    if _filepath is not None:
        return open(_filepath, 'w')
    return sys.stderr


argv_parse = sys.argv[1:]
for _arg in argv_parse:
    if not _arg.startswith("--"):
        continue
    _flag = _arg.split("=", 1)[0]
    _normalized = _flag[2:].replace("-", "_")
    if _normalized in REMOVED_OPTION_REPLACEMENTS:
        replacement = REMOVED_OPTION_REPLACEMENTS[_normalized]
        if replacement == "__MOVED_TO_EAGGL__":
            sys.stderr.write("Error: option %s moved to eaggl.py after repository split; run this in the eaggl repository\n" % _flag)
            sys.exit(2)
        if replacement is None:
            sys.stderr.write("Error: option %s has been removed and is no longer supported\n" % _flag)
            sys.exit(2)
        sys.stderr.write("Error: option %s has been removed; use %s instead\n" % (_flag, replacement))
        sys.exit(2)

(options, args) = parser.parse_args(argv_parse)
config_mode = None
option_lookup = {}
for _opt in _iter_parser_options(parser):
    for _long_opt in _opt._long_opts:
        option_lookup[_long_opt] = _opt

cli_specified_dests = set()
i = 0
while i < len(argv_parse):
    arg = argv_parse[i]
    if arg == "--":
        break
    if arg.startswith("--"):
        opt_token = arg.split("=", 1)[0]
        if opt_token in option_lookup:
            opt_obj = option_lookup[opt_token]
            if opt_obj.dest is not None:
                cli_specified_dests.add(opt_obj.dest)
            if "=" not in arg and opt_obj.takes_value() and i + 1 < len(argv_parse):
                i += 1
    i += 1

if options.config is not None:
    config_path = _resolve_config_path_value(options.config, os.getcwd())
    options.config = config_path
    config_dir = os.path.dirname(config_path)
    config_data = _load_json_config(config_path)
    config_mode = config_data["mode"] if "mode" in config_data else None
    if "options" in config_data:
        config_options = config_data["options"]
        if not isinstance(config_options, dict):
            bail("Config key 'options' must be a JSON object")
    else:
        config_options = dict(config_data)
        config_options.pop("mode", None)
        config_options.pop("include", None)

    dest_to_option = {}
    long_key_to_dest = {}
    for opt in _iter_parser_options(parser):
        dest_to_option[opt.dest] = opt
        for long_opt in opt._long_opts:
            key = long_opt.lstrip("-")
            long_key_to_dest[key] = opt.dest
            long_key_to_dest[key.replace("-", "_")] = opt.dest
    for raw_key, raw_value in config_options.items():
        if raw_key in ("mode", "options", "include"):
            continue

        normalized_config_key = raw_key
        if isinstance(normalized_config_key, str):
            if normalized_config_key.startswith("--"):
                normalized_config_key = normalized_config_key[2:]
            normalized_config_key = normalized_config_key.replace("-", "_")
        if normalized_config_key in REMOVED_OPTION_REPLACEMENTS:
            replacement = REMOVED_OPTION_REPLACEMENTS[normalized_config_key]
            if replacement == "__MOVED_TO_EAGGL__":
                bail("Config key '%s' moved to eaggl.py after repository split; run this in the eaggl repository" % raw_key)
            if replacement is None:
                bail("Config key '%s' has been removed in %s and is no longer supported" % (raw_key, config_path))
            replacement_config_key = replacement[2:].replace("-", "_") if replacement.startswith("--") else replacement
            bail("Config key '%s' has been removed in %s; use '%s' (CLI: %s) instead" % (raw_key, config_path, replacement_config_key, replacement))

        key = raw_key[2:] if isinstance(raw_key, str) and raw_key.startswith("--") else raw_key
        key_norm = key.replace("-", "_") if isinstance(key, str) else key
        if key in dest_to_option:
            dest = key
        elif key_norm in dest_to_option:
            dest = key_norm
        elif key in long_key_to_dest:
            dest = long_key_to_dest[key]
        elif key_norm in long_key_to_dest:
            dest = long_key_to_dest[key_norm]
        else:
            _early_warn("Ignoring unknown config key '%s' in %s" % (raw_key, config_path))
            continue

        if dest in cli_specified_dests:
            continue

        opt = dest_to_option[dest]
        if opt.action == "append":
            values = raw_value if isinstance(raw_value, list) else [raw_value]
            coerced_value = []
            for scalar in values:
                if scalar is None:
                    coerced_value.append(None)
                elif opt.type == "int":
                    coerced_value.append(int(scalar))
                elif opt.type == "float":
                    coerced_value.append(float(scalar))
                else:
                    coerced_value.append(scalar)
        elif opt.action in ("store_true", "store_false"):
            if isinstance(raw_value, bool):
                coerced_value = raw_value
            elif isinstance(raw_value, str):
                lower = raw_value.strip().lower()
                if lower in ("1", "true", "yes", "y", "on"):
                    coerced_value = True
                elif lower in ("0", "false", "no", "n", "off"):
                    coerced_value = False
                else:
                    bail("Config value for %s must be boolean" % (opt.dest))
            else:
                bail("Config value for %s must be boolean" % (opt.dest))
        elif opt.action == "callback":
            coerced_value = raw_value
        elif raw_value is None:
            coerced_value = None
        elif opt.type == "int":
            coerced_value = int(raw_value)
        elif opt.type == "float":
            coerced_value = float(raw_value)
        else:
            coerced_value = raw_value
        dest_lower = dest.lower() if dest is not None else ""
        is_path_like_dest = dest_lower.endswith("_in") or dest_lower.endswith("_out") or dest_lower.endswith("_file") or "_file_" in dest_lower or dest_lower in ("log_file", "warnings_file", "config")
        if is_path_like_dest:
            if isinstance(coerced_value, list):
                coerced_value = [_resolve_config_path_value(v, config_dir) if isinstance(v, str) else v for v in coerced_value]
            elif isinstance(coerced_value, str):
                coerced_value = _resolve_config_path_value(coerced_value, config_dir)
        setattr(options, dest, coerced_value)

if config_mode is not None:
    if len(args) < 1:
        args = [config_mode]
    elif args[0] != config_mode:
        _early_warn("Config mode '%s' differs from CLI mode '%s'; using CLI mode" % (config_mode, args[0]))

log_fh = _open_optional_log_handle(options.log_file)

NONE=0
INFO=1
DEBUG=2
TRACE=3
debug_level = INFO if options.debug_level is None else options.debug_level
def log(message, level=INFO, end_char='\n'):
    if level <= debug_level:
        log_fh.write("%s%s" % (message, end_char))
        log_fh.flush()

#set up warnings
warnings_fh = _open_optional_log_handle(options.warnings_file)

def warn(message):
    if warnings_fh is not None:
        warnings_fh.write("Warning: %s\n" % message)
        warnings_fh.flush()
    log(message, level=INFO)

if options.deterministic and options.seed is None:
    options.seed = 0
if options.seed is not None:
    random.seed(options.seed)
    np.random.seed(options.seed)
    log("Using deterministic random seed %d" % options.seed, INFO)

try:
    options.x_sparsify = [int(x) for x in options.x_sparsify]
except ValueError:
    bail("option --x-sparsify: invalid integer list %s" % options.x_sparsify)

if len(args) < 1:
    bail(usage)
mode = args[0]

factor_modes = set(["factor", "naive_factor"])
if mode in factor_modes:
    bail("Mode '%s' is not available in pigean.py after repository split; run this in the eaggl repository" % mode)

# ==========================================================================
# CLI Phase C: Mode resolution and mode-specific defaults.
