MODE_TO_STATE_KEYS = {
    "huge": ("run_huge",),
    "huge_calc": ("run_huge",),
    "beta_tildes": ("run_beta_tilde",),
    "beta_tilde": ("run_beta_tilde",),
    "betas": ("run_beta",),
    "beta": ("run_beta",),
    "priors": ("run_priors",),
    "prior": ("run_priors",),
    "naive_priors": ("run_naive_priors",),
    "naive_prior": ("run_naive_priors",),
    "gibbs": ("run_gibbs",),
    "em": ("run_gibbs",),
    "sim": ("run_sim",),
    "simulate": ("run_sim",),
    "pops": ("run_priors",),
    "naive_pops": ("run_naive_priors",),
}

def _set_default_option(_options, _name, _value):
    if getattr(_options, _name) is None:
        setattr(_options, _name, _value)


def _build_mode_state(_mode, _run_phewas_from_gene_phewas_stats_in):
    mode_state = {
        "run_huge": False,
        "run_beta_tilde": False,
        "run_beta": False,
        "run_priors": False,
        "run_naive_priors": False,
        "run_gibbs": False,
        "run_phewas": False,
        "run_sim": False,
    }
    state_keys = MODE_TO_STATE_KEYS.get(_mode)
    if state_keys is None:
        bail("Unrecognized mode %s" % _mode)
    for state_key in state_keys:
        mode_state[state_key] = True
    if _run_phewas_from_gene_phewas_stats_in is not None:
        mode_state["run_phewas"] = True
    return mode_state


_GIBBS_STOPPING_PRESETS = {
    "lenient": {
        "stop_mcse_quantile": 0.90,
        "max_rel_mcse_beta": 0.20,
        "max_abs_mcse_d": 0.10,
    },
    "strict": {
        "stop_mcse_quantile": 0.95,
        "max_rel_mcse_beta": 0.05,
        "max_abs_mcse_d": 0.03,
    },
}


def _flag_present_in_argv(_argv, *flag_names):
    for arg in _argv:
        for flag_name in flag_names:
            if arg == flag_name or arg.startswith(flag_name + "="):
                return True
    return False


def _set_memory_control_with_max_cap(_options, _argv, _derived, _clamped, opt_name, implied_max, flag_name):
    current = getattr(_options, opt_name)
    explicit = _flag_present_in_argv(_argv, flag_name)
    if current is None:
        new_value = implied_max
        _derived[opt_name] = new_value
    else:
        new_value = min(int(current), int(implied_max))
        if explicit and new_value < int(current):
            _clamped[opt_name] = (current, new_value, "max")
        elif not explicit and new_value != int(current):
            _derived[opt_name] = new_value
    setattr(_options, opt_name, int(new_value))


def _apply_mode_and_runtime_defaults(_options, _mode, _argv):
    # Mode-dependent defaults.
    if _mode in ("pops", "naive_pops"):
        _set_default_option(_options, "correct_betas_mean", False)
        _set_default_option(_options, "adjust_priors", False)
        _set_default_option(_options, "p_noninf", [1])
        _set_default_option(_options, "sigma_power", 2)
        _set_default_option(_options, "update_hyper", "none")
        _set_default_option(_options, "filter_negative", False)
        _set_default_option(_options, "prune_gene_sets", 1.1)
        _set_default_option(_options, "weighted_prune_gene_sets", 1.1)
        _set_default_option(_options, "top_gene_set_prior", 0.1)
        _set_default_option(_options, "num_gene_sets_for_prior", 15000)
        _set_default_option(_options, "filter_gene_set_p", 0.05)
        _set_default_option(_options, "linear", True)
        _set_default_option(_options, "max_for_linear", 1)
        _set_default_option(_options, "min_gene_set_size", 1)
        _set_default_option(_options, "cross_val", True)
        _set_default_option(_options, "sparse_frac_betas", 0)
        _set_default_option(_options, "sparse_solution", False)
    else:
        _set_default_option(_options, "correct_betas_mean", True)
        _set_default_option(_options, "adjust_priors", True)
        _set_default_option(_options, "p_noninf", [0.001])
        _set_default_option(_options, "sigma_power", -2)
        _set_default_option(_options, "update_hyper", "p")
        _set_default_option(_options, "filter_negative", True)
        _set_default_option(_options, "top_gene_set_prior", 0.8)
        _set_default_option(_options, "num_gene_sets_for_prior", 50)
        _set_default_option(_options, "filter_gene_set_p", 0.01)
        _set_default_option(_options, "linear", False)
        _set_default_option(_options, "max_for_linear", 0.95)
        _set_default_option(_options, "min_gene_set_size", 10)
        _set_default_option(_options, "cross_val", False)
        _set_default_option(_options, "sparse_frac_betas", 0.001)
        _set_default_option(_options, "sparse_solution", True)
        default_prune = 0.8
        if _options.prune_gene_sets is None:
            _options.prune_gene_sets = default_prune
        if _options.weighted_prune_gene_sets is None:
            _options.weighted_prune_gene_sets = default_prune

    # Gibbs stopping defaults.
    _options.gibbs_stopping_preset = "strict" if _options.strict_stopping else "lenient"
    for opt_name, opt_value in _GIBBS_STOPPING_PRESETS[_options.gibbs_stopping_preset].items():
        _set_default_option(_options, opt_name, opt_value)
    # Backward-compat defaults for simplified epoch controls.
    if _options.max_num_post_burn_in is None and _options.max_num_iter is not None:
        _options.max_num_post_burn_in = max(1, _options.max_num_iter - max(_options.min_num_burn_in, 0))
    # Explicitly disable all stall-based early exits/restarts.
    if _options.disable_stall_detection:
        _options.burn_in_stall_window = 0
        _options.stall_window = 0
        _options.stall_recent_window = 0
        # Emulate legacy single-epoch behavior: no restarts and one total Gibbs budget.
        _options.max_num_restarts = 0
        _options.total_num_iter_gibbs = _options.max_num_iter

    if _options.max_gb is None:
        _options.max_gb = 2.0
    if _options.max_gb <= 0:
        bail("Option --max-gb must be > 0")

    total_mb = int(round(_options.max_gb * 1024.0))
    baseline_gb = 2.0
    scale = _options.max_gb / baseline_gb
    if scale <= 0:
        scale = 1.0

    derived = {}
    clamped = {}
    implied = {}
    implied["batch_size_max"] = max(500, int(round(5000 * scale)))
    # Outer-Gibbs stacked-X is only one large buffer among many; keep it conservative.
    implied["gibbs_max_mb_X_h_max"] = max(32, int(round(total_mb * 0.20)))
    # read_X buffers Python object triplets (data,row,col); keep conservative for low-memory runs.
    implied["max_read_entries_at_once_max"] = max(100000, int(round(total_mb * 500)))
    implied["gibbs_num_batches_parallel_max"] = max(1, int(round(10 * scale)))
    if _options.num_chains is not None:
        implied["gibbs_num_batches_parallel_max"] = min(implied["gibbs_num_batches_parallel_max"], int(_options.num_chains))
    implied["pre_filter_small_batch_size_max"] = max(100, int(round(500 * scale)))
    implied["pre_filter_batch_size_max"] = max(implied["pre_filter_small_batch_size_max"], int(round(5000 * scale)))
    # For tighter memory budgets, increase gene batches; for looser budgets, reduce batches.
    # This is an inverse memory knob: larger values use less memory.
    implied["priors_num_gene_batches_min"] = max(1, int(np.ceil(20.0 / scale)))

    _set_memory_control_with_max_cap(_options, _argv, derived, clamped, "batch_size", implied["batch_size_max"], "--batch-size")
    _set_memory_control_with_max_cap(_options, _argv, derived, clamped, "gibbs_max_mb_X_h", implied["gibbs_max_mb_X_h_max"], "--gibbs-max-mb-X-h")
    _set_memory_control_with_max_cap(_options, _argv, derived, clamped, "max_read_entries_at_once", implied["max_read_entries_at_once_max"], "--max-read-entries-at-once")
    _set_memory_control_with_max_cap(_options, _argv, derived, clamped, "gibbs_num_batches_parallel", implied["gibbs_num_batches_parallel_max"], "--gibbs-num-batches-parallel")
    _set_memory_control_with_max_cap(_options, _argv, derived, clamped, "pre_filter_small_batch_size", implied["pre_filter_small_batch_size_max"], "--pre-filter-small-batch-size")
    if _options.pre_filter_batch_size is not None:
        _set_memory_control_with_max_cap(_options, _argv, derived, clamped, "pre_filter_batch_size", implied["pre_filter_batch_size_max"], "--pre-filter-batch-size")
    current = getattr(_options, "priors_num_gene_batches")
    explicit = _flag_present_in_argv(_argv, "--priors-num-gene-batches")
    if current is None:
        new_value = implied["priors_num_gene_batches_min"]
        derived["priors_num_gene_batches"] = new_value
    else:
        new_value = max(int(current), int(implied["priors_num_gene_batches_min"]))
        if explicit and new_value > int(current):
            clamped["priors_num_gene_batches"] = (current, new_value, "min")
        elif not explicit and new_value != int(current):
            derived["priors_num_gene_batches"] = new_value
    setattr(_options, "priors_num_gene_batches", int(new_value))

    log("Memory controls: --max-gb=%.3g (%.0f MB total), effective batch controls: max_read_entries_at_once=%d, priors_num_gene_batches=%d, gibbs_num_batches_parallel=%d, gibbs_max_mb_X_h=%d, batch_size=%d, pre_filter_batch_size=%s, pre_filter_small_batch_size=%d" % (_options.max_gb, total_mb, _options.max_read_entries_at_once, _options.priors_num_gene_batches, _options.gibbs_num_batches_parallel, _options.gibbs_max_mb_X_h, _options.batch_size, str(_options.pre_filter_batch_size), _options.pre_filter_small_batch_size), INFO)
    if len(derived) > 0:
        log("Derived from --max-gb (implicit/default adjustments): %s" % ", ".join(["%s=%s" % (k, derived[k]) for k in sorted(derived.keys())]), DEBUG)
    if len(clamped) > 0:
        log("Clamped by --max-gb: %s" % ", ".join(["%s:%s->%s(%s)" % (k, clamped[k][0], clamped[k][1], clamped[k][2]) for k in sorted(clamped.keys())]), INFO)


_apply_mode_and_runtime_defaults(options, mode, sys.argv[1:])

if options.gene_cor_file is None and options.gene_loc_file is None and not options.ols:
    warn("Switching to run --ols since --gene-cor-file and --gene-loc-file are unspecified")
    options.ols = True
if options.betas_from_phewas:
    options.betas_uncorrected_from_phewas = True

if options.print_effective_config:
    effective_config = {
        "mode": mode,
        "config": options.config,
        "options": _json_safe(vars(options)),
    }
    sys.stdout.write("%s\n" % json.dumps(effective_config, indent=2, sort_keys=True))
    sys.exit(0)

def urlopen_with_retry(file, flag=None, tries=5, delay=60, backoff=2):
    import urllib.request
    import urllib.error

    while tries > 1:
        try:
            if flag is not None:
                return urllib.request.urlopen(file, flag)
            else:
                return urllib.request.urlopen(file)
        except urllib.error.URLError as e:
            log("%s, Retrying in %d seconds..." % (str(e), delay))
            time.sleep(delay)
            tries -= 1
            delay *= backoff
    bail("Couldn't open file after too many retries")

_DIG_OPEN_DATA_PREFIX = "dig-open-data:"
_DIG_OPEN_DATA_TOKEN_RE = re.compile(r"^[A-Za-z0-9_.+-]+$")

def is_gz_file(filepath, is_remote, flag=None):

    if len(filepath) >= 3 and (filepath[-3:] == ".gz" or filepath[-4:] == ".bgz") and (flag is None or 'w' not in flag):
        try:
            if is_remote:
                test_fh = urlopen_with_retry(filepath)
            else:
                test_fh = gzip.open(filepath, 'rb')

            try:
                test_fh.readline()
                test_fh.close()
                return True
            except Exception:
                return False

        except FileNotFoundError:
            return True

    elif flag is None or 'w' not in flag:
        flag = 'rb'
        if is_remote:
            test_fh = urlopen_with_retry(filepath)
        else:
            test_fh = open(filepath, 'rb')

        is_gz = test_fh.read(2) == b'\x1f\x8b'
        test_fh.close()
        return is_gz
    else:
        return filepath[-3:] == ".gz" or filepath[-4:] == ".bgz"

def open_gz(file, flag=None):
    if isinstance(file, str) and file.startswith(_DIG_OPEN_DATA_PREFIX):
        if flag is not None and "w" in flag:
            bail("dig-open-data sources are read-only and cannot be opened for writing")

        spec = file[len(_DIG_OPEN_DATA_PREFIX):]
        if len(spec.strip()) == 0:
            bail("Invalid dig-open-data source '%s'; expected dig-open-data:<ancestry>:<trait>" % file)

        try:
            from dig_open_data import open_text, open_trait
        except ImportError:
            bail("dig_open_data is required to read '%s'. Install https://github.com/flannick/dig-open-data/" % file)

        is_ancestry_trait = False
        if spec.count(":") == 1:
            ancestry, trait = spec.split(":", 1)
            is_ancestry_trait = (
                len(ancestry) > 0
                and len(trait) > 0
                and "/" not in ancestry
                and "/" not in trait
                and _DIG_OPEN_DATA_TOKEN_RE.match(ancestry) is not None
                and _DIG_OPEN_DATA_TOKEN_RE.match(trait) is not None
            )
        if is_ancestry_trait:
            ancestry, trait = spec.split(":", 1)
            log("Reading dig-open-data trait ancestry=%s trait=%s" % (ancestry, trait), INFO)
            return open_trait(ancestry, trait)

        # Fallback: allow direct URIs/keys understood by dig_open_data.open_text.
        log("Reading dig-open-data source %s" % spec, INFO)
        return open_text(spec)

    is_remote = False
    remote_prefixes = ["http:", "https:", "ftp:"]
    for remote_prefix in remote_prefixes:
        if len(file) >= len(remote_prefix) and file[:len(remote_prefix)] == remote_prefix:
            is_remote = True

    if is_gz_file(file, is_remote, flag=flag):
        open_fun = gzip.open
        if flag is not None and len(flag) > 0 and not flag[-1] == 't':
            flag = "%st" % flag
        elif flag is None:
            flag = "rt"
    else:
        open_fun = open

    if is_remote:
        import io
        if flag is not None:
            if open_fun is open:
                fh = io.TextIOWrapper(urlopen_with_retry(file, flag))
            else:
                fh = open_fun(urlopen_with_retry(file), flag)
        else:
            if open_fun is open:
                fh = io.TextIOWrapper(urlopen_with_retry(file))
            else:
                fh = open_fun(urlopen_with_retry(file))
    else:
        if flag is not None:
            try:
                fh = open_fun(file, flag, encoding="utf-8")
            except LookupError:
                fh = open_fun(file, flag)
        else:
            try:
                fh = open_fun(file, encoding="utf-8")
            except LookupError:
                fh = open_fun(file)

    return fh

class GeneSetData(object):
    '''
    Stores gene and gene set annotations and derived matrices
    It allows reading X or V files and using these to determine the allowed gene sets and genes
    '''
    def __init__(self, background_prior=0.05, batch_size=4500):

        #empirical mean scale factor from mice
        self.MEAN_MOUSE_SCALE = 0.0448373

        if background_prior <= 0 or background_prior >= 1:
            bail("--background-prior must be in (0,1)")
        self.background_prior = background_prior
        self.background_log_bf = np.log(self.background_prior / (1 - self.background_prior))
        self.background_bf = np.exp(self.background_log_bf)
        self.debug_old_batch = False
        self.debug_skip_correlation = False
        self.debug_skip_phewas_covs = False
        self.debug_only_avg_huge = False
        self.debug_just_check_header = False

        self._init_matrix_and_gene_index_state(batch_size=batch_size)
        self._init_phewas_and_label_state()
        self._init_gene_set_regression_state()
        self._init_gene_signal_and_huge_state()
        self._init_model_summary_state()

    def _init_matrix_and_gene_index_state(self, batch_size):
        #genes x gene set indicator matrix (sparse)
        #this is always the original matrix -- it is never rescaled or shifted
        #but, calculations of beta_tildes etc. are done relative to what would be obtained if it were scaled
        #similarly, when X/y is whitened, the "internal state" of the code is that both X and y are whitened (and scale factors reflect this)
        #but, for efficiency, X is maintained as a sparse matrix
        #so, ideally this should never be accessed directly; instead get_X_orig returns the original (sparse) matrix and makes the intent explicity to avoid any scaling/whitening
        #get_X_blocks returns the (unscaled) but whitened X
        self.X_orig = None

        #binary representation of X
        self.X_binary_packed = None
        #these are genes that we want to calculate priors for but which don't have gene-level statistics
        self.X_orig_missing_genes = None
        self.X_orig_missing_genes_missing_gene_sets = None
        self.X_orig_missing_gene_sets = None
        #internal cache
        self.last_X_block = None

        #genes x gene set normalized matrix
        #REMOVING THIS for memory savings
        #self.X = None

